import React, { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import axios from "axios";
import "./home.css";

const Home = () => {
  const [user, setUser] = useState(null);
  const [isEditing, setIsEditing] = useState(false);
  const [newProfileImage, setNewProfileImage] = useState(null);
  const [newCoverImage, setNewCoverImage] = useState(null);
  const [error, setError] = useState(null);
  const navigate = useNavigate();

  useEffect(() => {
    const fetchUser = async () => {
      try {
        const token = localStorage.getItem("token");
        const response = await axios.get("http://localhost:5001/users/me", {
          headers: { Authorization: `Bearer ${token}` },
        });
        setUser(response.data);
      } catch (error) {
        console.error("Erreur lors de la récupération des données utilisateur", error);
        setError("Impossible de charger les données utilisateur.");
      }
    };
    fetchUser();
  }, []);

  const handleEdit = () => {
    setIsEditing(true);
  };

  const handleSave = async () => {
    if (!newProfileImage && !newCoverImage) {
      alert("Veuillez sélectionner une image à mettre à jour.");
      return;
    }

    try {
      const token = localStorage.getItem("token");
      const formData = new FormData();
      if (newProfileImage) formData.append("profileImage", newProfileImage);
      if (newCoverImage) formData.append("coverImage", newCoverImage);

      const response = await axios.put(`http://localhost:5001/users/${user.id}`, formData, {
        headers: { 
          Authorization: `Bearer ${token}`,
          "Content-Type": "multipart/form-data",
        },
      });
      setUser(response.data);
      setIsEditing(false);
    } catch (error) {
      console.error("Erreur lors de la mise à jour du profil", error);
      setError("Mise à jour échouée. Veuillez réessayer.");
    }
  };

  const handleLogout = () => {
    localStorage.removeItem("token");
    navigate("/login");
  };

  return (
    <div className="profile-container">
      {error && <p className="error-message">{error}</p>}
      {user ? (
        <>
          <div className="cover-photo" style={{ backgroundImage: `url(${user.coverImage})` }}>
            {isEditing && <input type="file" onChange={(e) => setNewCoverImage(e.target.files[0])} />}
          </div>
          <div className="profile-info">
            <img src={user.profileImage} alt="Profile" className="profile-pic" />
            {isEditing && <input type="file" onChange={(e) => setNewProfileImage(e.target.files[0])} />}
            <h2>{user.nom} {user.prenom}</h2>
            <p>Email: {user.email}</p>
            <p>Rôle: {user.role}</p>
            <button onClick={handleEdit}>Modifier le profil</button>
            {isEditing && <button onClick={handleSave}>Enregistrer</button>}
            <button onClick={handleLogout} className="logout-btn">Déconnexion</button>
          </div>
        </>
      ) : (
        <p>Chargement...</p>
      )}
    </div>
  );
};

export default Home;
